import{_ as a,o as e,c as s,aw as t}from"./chunks/framework.Dq2onT5h.js";const n=JSON.parse('{"title":"Data Availability","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Data Availability | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"concepts/data-availability.md","filePath":"concepts/data-availability.md","lastUpdated":1772446570000}');const l=a({name:"concepts/data-availability.md"},[["render",function(a,n,l,i,r,o){return e(),s("div",null,[...n[0]||(n[0]=[t('<h1 id="data-availability" tabindex="-1">Data Availability <a class="header-anchor" href="#data-availability" aria-label="Permalink to &quot;Data Availability&quot;">​</a></h1><p>Data availability (DA) ensures that all transaction data required to verify the chain&#39;s state is accessible to anyone.</p><h2 id="why-da-matters" tabindex="-1">Why DA Matters <a class="header-anchor" href="#why-da-matters" aria-label="Permalink to &quot;Why DA Matters&quot;">​</a></h2><p>Without data availability guarantees:</p><ul><li>Nodes can&#39;t verify state transitions</li><li>Users can&#39;t prove their balances</li><li>The chain&#39;s security model breaks down</li></ul><p>Evolve uses external DA layers to provide these guarantees, rather than storing all data on L1.</p><h2 id="how-evolve-handles-data-availability" tabindex="-1">How Evolve Handles Data Availability <a class="header-anchor" href="#how-evolve-handles-data-availability" aria-label="Permalink to &quot;How Evolve Handles Data Availability&quot;">​</a></h2><p>Evolve currently supports two DA modes:</p><h3 id="local-da" tabindex="-1">Local DA <a class="header-anchor" href="#local-da" aria-label="Permalink to &quot;Local DA&quot;">​</a></h3><ul><li><strong>Use case</strong>: Development and testing</li><li><strong>Guarantee</strong>: None (operator can withhold data)</li><li><strong>Latency</strong>: Instant</li></ul><h3 id="celestia" tabindex="-1">Celestia <a class="header-anchor" href="#celestia" aria-label="Permalink to &quot;Celestia&quot;">​</a></h3><ul><li><strong>Use case</strong>: Production deployments</li><li><strong>Guarantee</strong>: Data availability sampling (DAS)</li><li><strong>Latency</strong>: ~12 seconds to finality</li></ul><h2 id="da-flow" tabindex="-1">DA Flow <a class="header-anchor" href="#da-flow" aria-label="Permalink to &quot;DA Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Block Produced</span></span>\n<span class="line"><span>      │</span></span>\n<span class="line"><span>      ▼</span></span>\n<span class="line"><span>┌─────────────────┐</span></span>\n<span class="line"><span>│   Submitter     │  Queues block for DA</span></span>\n<span class="line"><span>└────────┬────────┘</span></span>\n<span class="line"><span>         │</span></span>\n<span class="line"><span>         ▼</span></span>\n<span class="line"><span>┌─────────────────┐</span></span>\n<span class="line"><span>│   DA Layer      │  Stores and orders data</span></span>\n<span class="line"><span>└────────┬────────┘</span></span>\n<span class="line"><span>         │</span></span>\n<span class="line"><span>         ▼</span></span>\n<span class="line"><span>┌─────────────────┐</span></span>\n<span class="line"><span>│   Full Nodes    │  Retrieve and verify</span></span>\n<span class="line"><span>└─────────────────┘</span></span></code></pre></div><h2 id="namespaces" tabindex="-1">Namespaces <a class="header-anchor" href="#namespaces" aria-label="Permalink to &quot;Namespaces&quot;">​</a></h2><p>Evolve uses DA namespaces to organize data:</p><table tabindex="0"><thead><tr><th>Namespace</th><th>Purpose</th></tr></thead><tbody><tr><td>Header</td><td>Block headers</td></tr><tr><td>Data</td><td>Transaction data</td></tr></tbody></table><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><ul><li><strong>Development</strong>: Use Local DA for fast iteration</li><li><strong>Testnet</strong>: Use Celestia testnet (Mocha or Arabica)</li><li><strong>Production</strong>: Use Celestia mainnet or equivalent</li></ul><h2 id="learn-more" tabindex="-1">Learn More <a class="header-anchor" href="#learn-more" aria-label="Permalink to &quot;Learn More&quot;">​</a></h2><ul><li><a href="/guides/da-layers/local-da">Local DA Guide</a></li><li><a href="/guides/da-layers/celestia">Celestia Guide</a></li><li><a href="/reference/interfaces/da">DA Interface Reference</a></li></ul>',21)])])}]]);export{n as __pageData,l as default};
